22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_RATE = 0.1;
24	const CURSE_SURCHARGE_RATE = 0.5;
25	const HIGH_ENCHANTMENT_THRESHOLD = 5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const BLOCK_SIZE = 3;
28	const BLOCK_PRICE = 60;
29	const COMPONENT_TYPES = ["rune", "moonstone"];
30	const LOYALTY_YEARS_THRESHOLD = 2;
31	const LOYALTY_DISCOUNT_RATE = 0.2;
32	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
33	
34	const BASE_PREMIUMS: Record<string, number> = {
35	  sword: 100,
36	  amulet: 60,
37	  staff: 80,
38	  potion: 40,
39	  rune: 25,
40	  moonstone: 25,
41	};
42	
43	const KNOWN_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion", "rune", "moonstone"]);
44	
45	function basePremiumFor(item: ItemSpec): number {
46	  return BASE_PREMIUMS[item.type] ?? 0;
47	}
48	
49	function sumBasePremiums(items: ItemSpec[]): number {
50	  return items.reduce((sum, item) => sum + basePremiumFor(item), 0);
51	}
52	
53	function countItemsOfType(items: ItemSpec[], type: string): number {
54	  return items.filter((item) => item.type === type).length;
55	}
56	
57	function blockAdjustmentFor(items: ItemSpec[], componentType: string): number {
58	  const count = countItemsOfType(items, componentType);
59	  if (count !== BLOCK_SIZE) return 0;
60	  return BLOCK_PRICE - BLOCK_SIZE * BASE_PREMIUMS[componentType];
61	}
62	
63	function blockAdjustment(items: ItemSpec[]): number {
64	  return COMPONENT_TYPES.reduce(
65	    (sum, componentType) => sum + blockAdjustmentFor(items, componentType),
66	    0
67	  );
68	}
69	
70	function isHighlyEnchanted(item: ItemSpec): boolean {
71	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
72	}
73	
74	function itemSurchargeFor(item: ItemSpec): number {
75	  let surcharge = 0;
76	  if (item.cursed) surcharge += basePremiumFor(item) * CURSE_SURCHARGE_RATE;
77	  if (isHighlyEnchanted(item)) surcharge += basePremiumFor(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE;
78	  return surcharge;
79	}
80	
81	function sumItemSurcharges(items: ItemSpec[]): number {
82	  return items.reduce((sum, item) => sum + itemSurchargeFor(item), 0);
83	}
84	
85	function qualifiesForLoyaltyDiscount(customer: Customer): boolean {
86	  return customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
87	}
88	
89	function loyaltyDiscountFor(customer: Customer, policyBasePremium: number): number {
90	  if (!qualifiesForLoyaltyDiscount(customer)) return 0;
91	  return policyBasePremium * LOYALTY_DISCOUNT_RATE;
92	}
93	
94	function followUpDiscountFor(customer: Customer, policyBasePremium: number): number {
95	  if ((customer.previousContracts ?? 0) <= 0) return 0;
96	  return policyBasePremium * FOLLOW_UP_DISCOUNT_RATE;
97	}
98	
99	function totalPolicyDiscount(customer: Customer, policyBasePremium: number): number {
100	  return (
101	    loyaltyDiscountFor(customer, policyBasePremium) +
102	    followUpDiscountFor(customer, policyBasePremium)
103	  );
104	}
