106	export function quote(input: QuoteInput): QuoteResult {
107	  const items = input.items;
108	  for (const item of items) {
109	    if (!KNOWN_ITEM_TYPES.has(item.type)) {
110	      throw new Error(`Unknown item type: ${item.type}`);
111	    }
112	  }
113	  const policyBasePremium = sumBasePremiums(items) + blockAdjustment(items);
114	  const itemSurcharges = sumItemSurcharges(items);
115	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_RATE;
116	  const policyDiscount = totalPolicyDiscount(input.customer, policyBasePremium);
117	  return {
118	    premium: Math.ceil(
119	      policyBasePremium + itemSurcharges + firstInsuranceSurcharge - policyDiscount + PROCESSING_FEE
120	    ),
121	  };
122	}
