124	export interface ClaimResult {
125	  payout: number;
126	  remainingCap: number;
127	}
128	
129	export interface DamageEntry {
130	  itemType: string;
131	  amount: number;
132	}
133	
134	export interface ClaimInput {
135	  items: ItemSpec[];
136	  damages: DamageEntry[];
137	  remainingCap?: number;
138	}
