140	const INSURANCE_VALUES: Record<string, number> = {
141	  sword: 1000,
142	  amulet: 600,
143	  staff: 800,
144	  potion: 400,
145	  rune: 250,
146	  moonstone: 250,
147	};
148	
149	const DEDUCTIBLE = 100;
150	const CAP_MULTIPLIER = 2;
151	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
152	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
153	
154	function insuranceValueFor(item: ItemSpec): number {
155	  return INSURANCE_VALUES[item.type] ?? 0;
156	}
157	
158	function sumInsuranceValues(items: ItemSpec[]): number {
159	  return items.reduce((sum, item) => sum + insuranceValueFor(item), 0);
160	}
161	
162	function findMatchingItem(items: ItemSpec[], itemType: string): ItemSpec | undefined {
163	  return items.find((item) => item.type === itemType);
164	}
165	
166	function triggersHighEnchantmentRule(item: ItemSpec | undefined): boolean {
167	  const enchantment = item?.enchantment ?? 0;
168	  return enchantment >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD;
169	}
170	
171	function reimbursementFor(damage: DamageEntry, item: ItemSpec | undefined): number {
172	  const reimbursableAmount = triggersHighEnchantmentRule(item)
173	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
174	    : damage.amount;
175	  return Math.max(0, reimbursableAmount - DEDUCTIBLE);
176	}
177	
178	function sumReimbursements(damages: DamageEntry[], items: ItemSpec[]): number {
179	  return damages.reduce(
180	    (sum, damage) => sum + reimbursementFor(damage, findMatchingItem(items, damage.itemType)),
181	    0
182	  );
183	}
184	
185	function defaultCapFor(items: ItemSpec[]): number {
186	  return CAP_MULTIPLIER * sumInsuranceValues(items);
187	}
