189	export function claim(input: ClaimInput): ClaimResult {
190	  const damageCountsByType: Record<string, number> = {};
191	  for (const damage of input.damages) {
192	    damageCountsByType[damage.itemType] = (damageCountsByType[damage.itemType] ?? 0) + 1;
193	  }
194	  for (const [itemType, damageCount] of Object.entries(damageCountsByType)) {
195	    const insuredCount = countItemsOfType(input.items, itemType);
196	    if (damageCount > insuredCount) {
197	      throw new Error(
198	        `Too many damage entries for ${itemType}: ${damageCount} damages but only ${insuredCount} insured`
199	      );
200	    }
201	  }
202	  for (const damage of input.damages) {
203	    if (damage.amount < 0) {
204	      throw new Error(`Damage amount must be non-negative: ${damage.amount}`);
205	    }
206	    if (findMatchingItem(input.items, damage.itemType) === undefined) {
207	      throw new Error(`Damage references item not in policy: ${damage.itemType}`);
208	    }
209	  }
210	  const remainingCap = input.remainingCap ?? defaultCapFor(input.items);
211	  const totalReimbursement = sumReimbursements(input.damages, input.items);
212	  const payout = Math.floor(Math.min(totalReimbursement, remainingCap));
213	  return { payout, remainingCap: remainingCap - payout };
214	}
